// Package genproto2 generates Go methods that directly encode/decode
// protobuf3 wire format bytes, without intermediate proto.Message structs.
// The generated bytes are identical to what amino.MarshalReflect produces.
package genproto2

import (
	"fmt"
	"os"
	"path"
	"reflect"
	"sort"
	"strings"
	"time"

	"github.com/gnolang/gno/tm2/pkg/amino"
	"github.com/gnolang/gno/tm2/pkg/amino/genproto"
)

// P3Context2 holds state for generating protobuf3 direct-encoding methods.
type P3Context2 struct {
	cdc           *amino.Codec
	targetPkgPath string            // import path of the package being generated
	imports       map[string]string // alias -> import path (accumulated during generation)
}

// NewP3Context2 creates a generator context with the given codec.
func NewP3Context2(cdc *amino.Codec) *P3Context2 {
	return &P3Context2{cdc: cdc}
}

// GenerateProtobuf3ForTypes generates source text for the given types.
// pkg is the Go package name for the generated file.
// The returned string is valid Go source.
func (ctx *P3Context2) GenerateProtobuf3ForTypes(pkg string, rtz ...reflect.Type) (string, error) {
	// Determine the target package path from the first non-interface type.
	ctx.targetPkgPath = ""
	for _, rt := range rtz {
		if rt.Kind() == reflect.Ptr {
			rt = rt.Elem()
		}
		if rt.Kind() != reflect.Interface && rt.PkgPath() != "" {
			ctx.targetPkgPath = rt.PkgPath()
			break
		}
	}

	// Initialize imports with always-needed packages.
	ctx.imports = map[string]string{
		"io":     "io",
		"fmt":    "fmt",
		"bytes":  "bytes",
		"errors": "errors",
		"amino":  "github.com/gnolang/gno/tm2/pkg/amino",
	}

	// Check if any type uses time.
	for _, rt := range rtz {
		if usesTime(ctx.cdc, rt) {
			ctx.imports["time"] = "time"
			break
		}
	}

	// Generate method bodies first (this accumulates extra imports via goTypeName).
	var body strings.Builder
	for _, rt := range rtz {
		info, err := ctx.cdc.GetTypeInfo(rt)
		if err != nil {
			return "", fmt.Errorf("GetTypeInfo(%v): %w", rt, err)
		}
		if info.Type.Kind() == reflect.Interface {
			continue
		}

		if err := ctx.generateMarshal(&body, info); err != nil {
			return "", fmt.Errorf("generateMarshal(%v): %w", rt, err)
		}
		if err := ctx.generateSize(&body, info); err != nil {
			return "", fmt.Errorf("generateSize(%v): %w", rt, err)
		}
		if err := ctx.generateUnmarshal(&body, info); err != nil {
			return "", fmt.Errorf("generateUnmarshal(%v): %w", rt, err)
		}
	}

	// Assemble final output with complete imports.
	var sb strings.Builder
	sb.WriteString("// Code generated by genproto2. DO NOT EDIT.\n\n")
	sb.WriteString(fmt.Sprintf("package %s\n\n", pkg))

	// Write imports sorted for deterministic output.
	sb.WriteString("import (\n")
	aliases := make([]string, 0, len(ctx.imports))
	for alias := range ctx.imports {
		aliases = append(aliases, alias)
	}
	sort.Strings(aliases)
	for _, alias := range aliases {
		p := ctx.imports[alias]
		if alias == pathBase(p) {
			sb.WriteString(fmt.Sprintf("\t%q\n", p))
		} else {
			sb.WriteString(fmt.Sprintf("\t%s %q\n", alias, p))
		}
	}
	sb.WriteString(")\n\n")

	// Suppress unused import warnings.
	sb.WriteString("var _ io.Writer\n")
	sb.WriteString("var _ fmt.Stringer\n")
	sb.WriteString("var _ *amino.Codec\n")
	sb.WriteString("var _ bytes.Buffer\n")
	sb.WriteString("var _ = errors.New\n")
	if _, ok := ctx.imports["time"]; ok {
		sb.WriteString("var _ time.Time\n")
	}
	sb.WriteString("\n")

	sb.WriteString(body.String())

	return sb.String(), nil
}

// WriteProtobuf3 generates pb3_gen.go in the package's directory.
func (ctx *P3Context2) WriteProtobuf3(pkg *amino.Package) {
	filename := path.Join(pkg.DirName, "pb3_gen.go")
	fmt.Printf("writing pb3 gen to %v for package %v\n", filename, pkg)
	err := ctx.WriteProtobuf3ForTypes(filename, pkg.GoPkgName, pkg.ReflectTypes()...)
	if err != nil {
		panic(err)
	}
}

// WriteProto3Schema generates the .proto schema file for a package,
// exactly as genproto.WriteProto3Schema does.
func (ctx *P3Context2) WriteProto3Schema(pkg *amino.Package) {
	genproto.WriteProto3Schema(pkg)
}

// WriteProtobuf3ForTypes generates and writes source to the given filename.
func (ctx *P3Context2) WriteProtobuf3ForTypes(filename, pkg string, rtz ...reflect.Type) error {
	src, err := ctx.GenerateProtobuf3ForTypes(pkg, rtz...)
	if err != nil {
		return err
	}
	return os.WriteFile(filename, []byte(src), 0o644)
}

// typeName returns the Go type name suitable for method receivers.
func typeName(info *amino.TypeInfo) string {
	return info.Type.Name()
}

// pathBase returns the last element of a package path.
func pathBase(p string) string {
	if i := strings.LastIndex(p, "/"); i >= 0 {
		return p[i+1:]
	}
	return p
}

// goTypeName returns a Go source representation of a reflect.Type,
// qualifying cross-package types and accumulating imports as needed.
func (ctx *P3Context2) goTypeName(rt reflect.Type) string {
	// Handle well-known types that need package qualification.
	if rt == reflect.TypeOf(time.Time{}) {
		return "time.Time"
	}
	if rt == reflect.TypeOf(time.Duration(0)) {
		return "time.Duration"
	}

	switch rt.Kind() {
	case reflect.Ptr:
		return "*" + ctx.goTypeName(rt.Elem())
	case reflect.Slice:
		return "[]" + ctx.goTypeName(rt.Elem())
	case reflect.Array:
		return fmt.Sprintf("[%d]%s", rt.Len(), ctx.goTypeName(rt.Elem()))
	case reflect.Map:
		return fmt.Sprintf("map[%s]%s", ctx.goTypeName(rt.Key()), ctx.goTypeName(rt.Elem()))
	case reflect.Interface:
		if rt.NumMethod() == 0 {
			return "any"
		}
		return ctx.qualifiedName(rt)
	default:
		name := rt.Name()
		if name != "" {
			pkgPath := rt.PkgPath()
			if pkgPath != "" && pkgPath != ctx.targetPkgPath {
				return ctx.qualifiedName(rt)
			}
			return name
		}
		return rt.String()
	}
}

// qualifiedName returns a package-qualified name for a cross-package type
// and ensures the import is registered.
func (ctx *P3Context2) qualifiedName(rt reflect.Type) string {
	pkgPath := rt.PkgPath()
	if pkgPath == "" || pkgPath == ctx.targetPkgPath {
		return rt.Name()
	}
	// Extract the actual Go package name from rt.String() (e.g., "cstypes.RoundState" → "cstypes").
	alias := pathBase(pkgPath)
	name := rt.Name()
	fullStr := rt.String()
	if dotIdx := strings.LastIndex(fullStr, "."); dotIdx >= 0 {
		alias = fullStr[:dotIdx]
	}
	// Disambiguate if alias collides with the target package name.
	targetBase := pathBase(ctx.targetPkgPath)
	if alias == targetBase {
		parts := strings.Split(pkgPath, "/")
		if len(parts) >= 2 {
			alias = parts[len(parts)-2] + "_" + alias
		}
	}
	// Check for collisions with existing imports pointing to different packages.
	if existing, ok := ctx.imports[alias]; ok && existing != pkgPath {
		parts := strings.Split(pkgPath, "/")
		if len(parts) >= 2 {
			alias = parts[len(parts)-2] + "_" + alias
		}
	}
	ctx.imports[alias] = pkgPath
	return alias + "." + name
}

// usesTime checks if any field of the type (or the type itself) is time.Time or time.Duration.
func usesTime(cdc *amino.Codec, rt reflect.Type) bool {
	visited := make(map[reflect.Type]bool)
	return _usesTime(cdc, rt, visited)
}

func _usesTime(cdc *amino.Codec, rt reflect.Type, visited map[reflect.Type]bool) bool {
	if rt.Kind() == reflect.Ptr {
		rt = rt.Elem()
	}
	if rt == reflect.TypeOf(time.Time{}) || rt == reflect.TypeOf(time.Duration(0)) {
		return true
	}
	if rt.Kind() != reflect.Struct {
		return false
	}
	if visited[rt] {
		return false
	}
	visited[rt] = true
	info, err := cdc.GetTypeInfo(rt)
	if err != nil {
		return false
	}
	for _, f := range info.Fields {
		ft := f.Type
		if ft.Kind() == reflect.Ptr {
			ft = ft.Elem()
		}
		if ft == reflect.TypeOf(time.Time{}) || ft == reflect.TypeOf(time.Duration(0)) {
			return true
		}
		if ft.Kind() == reflect.Struct {
			if _usesTime(cdc, ft, visited) {
				return true
			}
		}
	}
	return false
}
